var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"취향과 다르게 아기자기한 곳에 머물고 계셨네요, 세라펠.","JPN":"好みとは違って可愛らしいところに住んでいるんですね、セラフェル。","ENG":"What a cute and cozy place you're staying at, Serapel. It doesn't really suit you, right?","TWN":"跟你的喜好不同，你住的地方很可愛呢，塞拉費爾。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"그렇지. 주인이 없을 때는 이런 곳에라도 머물러야 마음이 진정돼.","JPN":"そうね。マスターがいない時にはこんなところにでもいないと心が落ち着かないの。","ENG":"Yes. When my master isn't around, staying in a place like this helps to calm my nerves.","TWN":"是啊。主人不在的時候，至少要待在這樣的地方，我的心才會平靜。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"아아, 흥분돼서 당장이라도 확인하고 싶구나.","JPN":"ああ、興奮してしまって、今すぐにでも確認したくてたまらないわ。","ENG":"Ahh... I'm so aroused I want to check right away.","TWN":"啊啊，我太激動了，好想馬上就確認啊。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"그 아이가……. 메이의 핏줄이 내게 다시 한 번 타오르는 고통을 느끼게 해 줄 수 있을지.","JPN":"あの子が……メイの血筋が私にもう一度燃え上げるような苦痛を味わわせてくれるかどうか。","ENG":"That child... I want to see if May's bloodline will gift me that burning pain once more.","TWN":"那孩子……梅伊的血脈究竟能否讓我再次感受到燃燒的痛苦。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"너무 걱정 마세요. 늑대의 송곳니가 기다리고 있을 테니까요.","JPN":"そう心配することはありません。狼の牙が待っているはずですから。","ENG":"Don't worry so much. The Wolf's fang will be waiting for you.","TWN":"別太擔心了。狼牙應該在等著你呢。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"후후, 쉽게 넘길 생각도 없으면서 말만큼은 여전히 달콤하구나.","JPN":"ふふ、簡単に渡すつもりもないくせに、言葉だけは相変わらずうまいのね。","ENG":"Fu fu. Your hollow words are like honey, even though I know you don't want to give her up so easily.","TWN":"呵呵，你明明不會輕易讓給我，卻還說得這麼好聽。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"하지만 정말로 왔군. 속삭이는 자의 사도에게 전해 들었을 때는 믿지 않았건만.","JPN":"それにしても、本当に来るとはね。囁く者の使徒から聞いた時には信じていなかったけど。","ENG":"Anyway, you did come to me. I didn't believe what the Apostle of the Whisperer told though.","TWN":"不過你真的來了啊。低語者的使徒告訴我時我還不相信。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"네 애완동물 건은 미안하게 됐다. 오랜만에 깨어난 나머지 조금 과하게 사용했던가.","JPN":"あなたのペットの件は悪かったわ。久々に目覚めたせいか、少し力を使いすぎてしまったみたい。","ENG":"I'm sorry about what happened to your pet. Did I overuse it after I awoke from a long slumber?","TWN":"你的寵物那件事，真對不起了。因為太久沒有醒來，我好像有點使用過度了。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"확실히 나쁘진 않았어. 그토록 강한 생기를 지닌 자는 어떻게 찾았지?","JPN":"確かに悪くはなかったわ。あれほど強い生気を持った人間をどうやって探し出したの？","ENG":"It wasn't bad at all. How did you come across someone with such vigor?","TWN":"不過確實很不錯。那麼充滿活力的人，你是怎麼找到的？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"……잠시 협력하는 사이에게 거기까지 답변해 드릴 이유는 없을 것 같네요.","JPN":"……一時的に協力する間柄で、そこまで答えなければならない理由はないと思います。","ENG":"...We don't see why we have to answer you when our brief partnership is coming to an end.","TWN":"……大家只是暫時合作的關係，我們好像沒理由回答你的問題。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"질문의 의도가 저희를 자극해서 고통 받기 위해서라는 점 때문에, 더더욱.","JPN":"質問の意図が我々を刺激して苦痛を受けようとするためなら、なおさら。","ENG":"Also, because your intention is to use our response to feel pain.","TWN":"而且如果你提問的意圖是刺激我們讓我們痛苦，那我們就更沒必要回答了。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"후훗. 떨어져 나온 단말 주제에 영리한 척 굴긴.","JPN":"ふふっ。遠隔端末風情がずいぶんお利巧なことを言うのね。","ENG":"Hah hah. A mere piece trying to be clever, I see.","TWN":"呵呵，只是一個分身而已，裝什麼聰明。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"그래서, 새로운 <color=#ffd34c>주인</color>은 어디에 있나요?","JPN":"ところで、新しい<color=#ffd34c>マスター</color>はどこにいるのですか？","ENG":"So? Where is your new <color=#ffd34c>master</color>?","TWN":"所以，新<color=#ffd34c>主人</color>在哪裡？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"잠시 협력하는 사이에게 거기까지 답변해 줘야 하던가?","JPN":"一時的に協力する間柄で、そこまで答える必要があるのかしら。","ENG":"I don't need to answer you too, do I?","TWN":"大家只是暫時合作的關係，我有必要回答你的問題嗎？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"그렇네요. 이번에는 한 입에 삼켜지지 않길 바랄게요.","JPN":"それもそうですね。今度はひと口にのみ込まれないといいですね。","ENG":"Fair enough. We hope she doesn't get swallowed in one bite this time.","TWN":"是啊。希望這次不會被我們一口吞掉。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"아. 잠시만요.","JPN":"あ、少々お待ちを。","ENG":"Oh, one moment, please.","TWN":"啊，等一下。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"네, 교수님. 말씀하세요.","JPN":"はい、教授。どうぞ。","ENG":"Yes, Professor?","TWN":"喂，教授，你請說。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};